const tag = 'zz' + Date.now().toString().slice(-6);
return [{
  json: {
    tag,
    chat_id: '919148969183',
    test_mode: true,
    manual_message: tag + ' milk 40 20\n' + tag + ' rice 60 25',
    promo_message: '10% off ' + tag + ' rice',
  },
}];

const seed = $('Seed Test Inputs').first().json || {};
const response = $('Run Inventory Preview').first().json || {};
const buttons = Array.isArray(response.buttons) ? response.buttons : [];
const confirm = buttons.find((button) => String(button.id || '').startsWith('owner_inv_confirm__'));
return [{
  json: {
    ...seed,
    response,
    confirm_id: confirm ? String(confirm.id) : '',
  },
}];

