const setup = $('Run Owner Setup').first().json || {};
const invPreview = $('Run Inventory Preview').first().json || {};
const invApply = $('Run Inventory Confirm').first().json || {};
const promoPreview = $('Run Promo Preview').first().json || {};
const promoApply = $('Run Promo Confirm').first().json || {};
const importPreview = $('Run Image Import Preview').first().json || {};
const importApply = $('Run Image Import Confirm').first().json || {};
const dbRows = $('Verify Test Rows').all().map((item) => item.json || {});
const seed = $('Seed Test Inputs').first().json || {};

return [{
  json: {
    tag: seed.tag,
    setup_text: String(setup.body_text || ''),
    inventory_preview_text: String(invPreview.body_text || ''),
    inventory_apply_text: String(invApply.body_text || ''),
    promo_preview_text: String(promoPreview.body_text || ''),
    promo_apply_text: String(promoApply.body_text || ''),
    image_import_preview_text: String(importPreview.body_text || ''),
    image_import_apply_text: String(importApply.body_text || ''),
    db_rows: dbRows,
    checks: {
      inventory_preview_has_confirm: Array.isArray(invPreview.buttons) && invPreview.buttons.some((button) => String(button.id || '').startsWith('owner_inv_confirm__')),
      inventory_apply_ok: /catalog updated/i.test(String(invApply.body_text || '')),
      promo_preview_has_confirm: Array.isArray(promoPreview.buttons) && promoPreview.buttons.some((button) => String(button.id || '').startsWith('owner_promo_confirm__')),
      promo_apply_ok: /discount saved/i.test(String(promoApply.body_text || '')),
      image_import_preview_has_confirm: Array.isArray(importPreview.buttons) && importPreview.buttons.some((button) => String(button.id || '').startsWith('owner_inv_confirm__')),
      image_import_apply_ok: /catalog updated/i.test(String(importApply.body_text || '')),
      db_has_inventory_rows: dbRows.some((row) => row.kind === 'inventory'),
      db_has_promo_rows: dbRows.some((row) => row.kind === 'promo'),
    },
  },
}];
